@app.route('/api/users')
def list_users():
    # API endpoint to list users
    # Returns a list of all users in the system
    print('Fetching all users')

    users = User.objects.all()

    results = []
    for user in users:
        # PROBLEM: Serializing entire object including sensitive/internal fields
        # sending 'password_hash', 'internal_notes', 'audit_logs' over the wire
        # wastes bandwidth and exposes data.
        # This is strictly a Response Construction issue.
        # Should select specific fields (DTO pattern) like {'id': user.id, 'name': user.name}
        results.append(user.to_full_dict())

    return jsonify(results)
